 async function acceptPlanRow(row){
  const r=row.candidate||row,created=new Date().toISOString();
  try{await transaction(async db=>{insertRecord(db,'planned_meals',{planned_at:`${row.date}T12:00:00`,planned_local_date:row.date,meal_type:row.slot||'Meal',food_id:r.food_id||null,food_name:row.food_name||r.item||r.name||'Planned meal',amount:1,unit:r.unit||'serving',...nutrientSnapshot(canonicalNutrition({...r,...(row.nutrition||{})})),notes:JSON.stringify({source:'adaptive_plan',planning_score:row.planningScore||null}),status:'planned',created_at:created,updated_at:created,pantry_id:r.pantry_id||null,source_type:row.source_type||'food',lock_state:row.lock_state||'flexible'})});setSaved(`${row.food_name||r.item||r.name||'Meal'} added to the plan`);setPlanDetail(null);setTimeout(()=>setSaved(''),1800)}catch(e){setSaved(e.message||String(e))}
 }
