function RecipeCreateEditor({foods,onClose,onSaved}){
 const first=foods[0]||null;
 const makeRow=()=>({key:`ingredient-${Date.now()}-${Math.random().toString(36).slice(2,7)}`,food_id:first?.food_id||'',amount:first?.default_serving||1,unit:first?.unit||'serving'});
 const [name,setName]=useState(''),[ingredients,setIngredients]=useState(()=>[makeRow()]),[error,setError]=useState(''),[saving,setSaving]=useState(false);
 function updateRow(key,patch){setIngredients(rows=>rows.map(row=>row.key===key?{...row,...patch}:row))}
 function chooseIngredient(key,foodId){const food=foods.find(item=>item.food_id===foodId);updateRow(key,{food_id:foodId,amount:food?.default_serving||1,unit:food?.unit||'serving'})}
 function addIngredient(){setIngredients(rows=>[...rows,makeRow()])}
 function removeIngredient(key){setIngredients(rows=>rows.length===1?rows:rows.filter(row=>row.key!==key))}
 async function save(){
  setError('');const recipeName=name.trim();
  if(!recipeName){setError('Enter a recipe name.');return}
  const resolved=ingredients.map(row=>({...row,food:foods.find(item=>item.food_id===row.food_id)}));
  if(!resolved.length||resolved.some(row=>!row.food)){setError('Choose a food for every ingredient.');return}
  if(resolved.some(row=>!Number(row.amount)||Number(row.amount)<=0)){setError('Every ingredient needs a quantity greater than zero.');return}
  if(new Set(resolved.map(row=>row.food_id)).size!==resolved.length){setError('Each ingredient can appear only once.');return}
  if(query('SELECT 1 FROM recipes WHERE LOWER(recipe_name)=LOWER(?) AND COALESCE(archived,0)=0 LIMIT 1',[recipeName]).length){setError('A recipe with this name already exists.');return}
  const recipeId=`R${Date.now()}`,now=new Date().toISOString();setSaving(true);
  try{
   await transaction(async db=>{for(const row of resolved)insertRecord(db,'recipes',{recipe_id:recipeId,recipe_name:recipeName,ingredient_name:row.food.name,amount:Number(row.amount),unit:row.unit||row.food.unit||'serving',ingredient_type:'food',ingredient_id:row.food.food_id,inventory_status:'linked',archived:0,archived_at:null,created_at:now,updated_at:now})});
   onSaved?.(recipeName,recipeId);
  }catch(err){setError(err instanceof Error?err.message:String(err))}finally{setSaving(false)}
 }
 return <div className="modal-backdrop recipe-create-modal" onClick={onClose}><div className="panel fixed-editor recipe-create-editor" onClick={e=>e.stopPropagation()}><div className="edit-head sticky-head"><button type="button" className="header-icon-action" onClick={onClose} aria-label="Close recipe editor"><X/></button><div><small>RECIPE</small><h3>New Recipe</h3><em>Build a reusable meal from foods</em></div><button type="button" className="header-icon-action save-action" onClick={save} disabled={saving} aria-label="Save recipe">{saving?'…':<Check/>}</button></div><div className="editor-scroll"><label>Recipe name<input autoFocus value={name} onChange={e=>setName(e.target.value)} placeholder="Example: Salmon Power Salad"/></label><section className="recipe-ingredient-editor"><div className="section-title"><b>Ingredients</b><button type="button" onClick={addIngredient}><Plus/> Add ingredient</button></div>{ingredients.map((row,index)=><article className="recipe-ingredient-row" key={row.key}><div className="recipe-ingredient-number">{index+1}</div><div className="recipe-ingredient-fields"><label>Food<select value={row.food_id} onChange={e=>chooseIngredient(row.key,e.target.value)}><option value="">Choose a food</option>{foods.map(food=><option key={food.food_id} value={food.food_id}>{food.name}</option>)}</select></label><div className="amount unit-amount"><label>Quantity<input type="number" inputMode="decimal" min="0.01" step="0.01" value={row.amount} onChange={e=>updateRow(row.key,{amount:e.target.value})}/></label><label>Unit<input value={row.unit} onChange={e=>updateRow(row.key,{unit:e.target.value})}/></label></div></div><button type="button" className="recipe-remove-ingredient" onClick={()=>removeIngredient(row.key)} disabled={ingredients.length===1} aria-label={`Remove ingredient ${index+1}`}><Trash2/></button></article>)}</section>{!foods.length&&<div className="inline-error">Create at least one food before creating a recipe.</div>}{error&&<div className="inline-error">{error}</div>}</div></div></div>
}

