 const request=useMemo(()=>JSON.stringify({format:'fizz-health-exchange',schema_version:3,request_type:'universal_exchange',request_id:`restaurant-${operation}-${Date.now()}`,operation,target:{type:meal?'restaurant_menu_item':'restaurant',id:meal?.id||restaurant?.restaurant_id||null,create_if_missing:operation==='create_restaurant'},instructions:{purpose:operation==='replace_menu'?'Replace or enrich this restaurant menu from attached evidence.':operation==='enrich_menu_item'?'Enrich this specific restaurant menu item from attached evidence.':'Create and enrich this restaurant profile and menu from attached evidence.',rules:['Return only one valid JSON object.','Do not embed or return photos, PDFs, or binary data.','Use null for unknown values and include confidence and evidence notes.']},existing_record:{restaurant,menu_item:meal||null},proposed_record:null,analysis:{},review:{requires_user_approval:true}},null,2),[restaurant,meal,operation]);
