 return <><div className="standard-page-head"><button onClick={done} aria-label="Close restaurants"><X/></button><h2>Restaurants</h2><button onClick={()=>setCreating(true)} aria-label="Add restaurant"><Plus/></button></div><header><Brand/><small>RESTAURANT INTELLIGENCE</small><h1>Restaurants</h1><p>{restaurants.length} {showArchived?'archived':'active'} profiles</p></header><button className="archive-toggle" onClick={()=>setShowArchived(x=>!x)}>{showArchived?'Show active restaurants':'Show archived restaurants'}</button><div className="list restaurant-list">{restaurants.map(r=><button className="item" key={r.restaurant_id} onClick={()=>setSelectedId(r.restaurant_id)}><div><b>{r.name}</b><span>{r.cuisine||'Cuisine not specified'} · {r.location||r.address||'Location not specified'}{Number(r.favorite)===1?' · Favorite':''}</span></div><UtensilsCrossed/></button>)}</div>{!restaurants.length&&<div className="empty">{showArchived?'No archived restaurants.':'Tap + to add a restaurant.'}</div>}{editor}</>
